fun launchAppByName(appName: String): Boolean {
    val pm = packageManager
    val mainIntent = android.content.Intent(android.content.Intent.ACTION_MAIN, null)
    mainIntent.addCategory(android.content.Intent.CATEGORY_LAUNCHER)

    val apps = pm.queryIntentActivities(mainIntent, 0)

    // 1. Try Exact Match
    var target = apps.find { it.loadLabel(pm).toString().equals(appName, ignoreCase = true) }

    // 2. Try Fuzzy (Contains)
    if (target == null) {
        target = apps.find { it.loadLabel(pm).toString().contains(appName, ignoreCase = true) }
    }

    return if (target != null) {
        val launchIntent = pm.getLaunchIntentForPackage(target.activityInfo.packageName)
        if (launchIntent != null) {
            launchIntent.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
            startActivity(launchIntent)
            true
        } else false
    } else {
        false
    }
}

    "recents" -> a11y?.performAction(android.accessibilityservice.AccessibilityService.GLOBAL_ACTION_RECENTS)
    "wait" -> waitTime = args.optLong("seconds", 2) * 1000L
    "open_app" -> {
        val name = args.optString("name")
        val success = a11y?.launchAppByName(name) ?: false
        if (!success) DebugLogManager.log("APP_LAUNCH", "Failed to find app: $name")
        waitTime = 3000L // Give app time to load before next capture
    }
}

